brain:
var s=context.state,a=context.action,m=context.memory;
var PI2=Math.PI*2,PI=Math.PI;
if(!m.t){m.t=0;m.lf=-99;m.d=1;}m.t++;
var angDiff=function(x,y){var d=(x-y)%PI2;if(d>PI)d-=PI2;if(d<-PI)d+=PI2;return d;};
var angTo=function(x1,y1,x2,y2){return Math.atan2(y2-y1,x2-x1);};
var myX=s.position.x,myY=s.position.y,myA=s.angle;
var dC=Math.sqrt((myX-450)*(myX-450)+(myY-450)*(myY-450));
var toC=s.angleToCenter;
var rem=context.round.remaining;
var closest=s.proximity[0]||{};
var front=s.scanner.robot[0]||false;
var eProj=s.scanner.projectile[0]||false;
if(rem<5){
  if(dC>8){a.desiredAngle=toC;a.desiredForce=s.maxForce;}
  else a.desiredForce=0;
}else if(rem<25){
  if(dC>180){
    a.desiredAngle=toC;a.desiredForce=s.maxForce*0.7;
    a.desiredScan=120;
  }else if(dC>60){
    a.desiredAngle=toC+m.d*0.35;
    a.desiredForce=s.maxForce*0.25;
    a.desiredScan=180;
  }else{
    a.desiredAngle=myA+m.d*0.05;
    a.desiredForce=s.maxForce*0.04;
    a.desiredScan=220;
    if(m.t%80===0)m.d=-m.d;
  }
  if(eProj&&eProj.range<110){
    var inc=(eProj.angleFromRobot+PI)%PI2;
    var pD=Math.abs(angDiff(eProj.angle,inc));
    if(pD<0.6){
      var pL=eProj.angleFromRobot+PI/2;
      var pR=eProj.angleFromRobot-PI/2;
      var dL=Math.abs(angDiff(pL,toC));
      var dR=Math.abs(angDiff(pR,toC));
      a.desiredAngle=(dL<dR)?pL:pR;
      a.desiredForce=s.maxForce*0.7;
    }
  }
  var enemy=false;
  for(var i=0;i<s.scanner.robot.length;i++){
    var rb=s.scanner.robot[i];
    if(rb.active&&(!enemy||rb.range<enemy.range))enemy=rb;
  }
  if(enemy){
    var range=enemy.range;
    var projSpeed=42;
    var tF=range/projSpeed;
    var pX=enemy.x+enemy.speed*Math.cos(enemy.angle)*tF;
    var pY=enemy.y+enemy.speed*Math.sin(enemy.angle)*tF;
    var lA=angTo(myX,myY,pX,pY);
    a.desiredAngle=lA;
    var aimErr=Math.abs(angDiff(myA,lA));
    var tgtW=Math.atan2(28,range);
    if(aimErr<tgtW&&(m.t-m.lf)>=30){a.desiredLaunch=true;m.lf=m.t;}
    a.desiredScan=Math.max(80,Math.min(300,range*0.8));
  }
  for(var j=0;j<s.proximity.length;j++){
    var p=s.proximity[j];
    if(p.entityType==='robot'&&p.range<40){
      a.desiredAngle=(p.angleFromRobot+PI)%PI2;
      a.desiredForce=s.maxForce*0.5;break;
    }
  }
}else{
  if(Math.random()<0.5)a.desiredForce=s.maxForce;
  if(closest.entityType=="wall"){
    a.desiredAngle=toC;
  }else if(front&&front.active&&front.team!=s.team){
    a.desiredAngle=front.angleFromRobot;
    a.desiredLaunch=true;
  }else if(front){
    var dir2=(front.angleFromRobot-myA)<0?-1:1;
    a.desiredAngle=myA-(dir2*0.174533);
    a.desiredForce=s.maxForce/2;
  }else if(Math.random()<0.005){
    var maxvar=PI/4;
    a.desiredAngle=myA+(Math.random()*maxvar)-maxvar/2;
    a.desiredForce=0;
  }
}
if(myX<55||myX>845||myY<55||myY>845){a.desiredAngle=toC;a.desiredForce=s.maxForce;}
